fn find_max<T: PartialOrd>(slice: &[T]) -> Option<&T> {
    if slice.is_empty() {
        return None;
    }
    let mut max = &slice[0];
    for item in &slice[1..] {
        if item > max {
            max = item;
        }
    }
    Some(max)
}

The PartialOrd trait bound is required because the > comparison operator is defined by this trait. Without it, the compiler cannot guarantee that the type T supports comparison, and the code would not compile. This is the benefit of bounded generics: the compiler enforces that the function is only called with types that support the required operations.

import time
from functools import wraps

def retry(max_attempts=3, delay=1):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            last_exception = None
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    last_exception = e
                    if attempt < max_attempts - 1:
                        time.sleep(delay)
            raise last_exception
        return wrapper
    return decorator
